from typing import List

class Solution:
    def mostWordsFound(self, sentences: List[str]) -> int:
        # Split each sentence into words and count the number of words
        word_counts = [len(sentence.split()) for sentence in sentences]
        # Return the maximum word count found
        return max(word_counts)
```

This solution iterates over each sentence in the input list, splits the sentence into words using the `split()` method, counts the number of words, and then finds the maximum word count among all sentences.
